// Gera resposta curta baseada na ação executada
const acao = $input.first().json;

const emojis = {
  criar_nota: '📝',
  criar_reuniao: '📅',
  criar_task: '✅',
  registrar_decisao: '🎯',
  atualizar_status: '🔄',
  consultar_tasks: '📋',
  registrar_lancamento: '💰',
  criar_daily: '📆'
};

const emoji = emojis[acao.acao] || '✅';
const resposta = `${emoji} ${acao.conteudo.slice(0, 80)}\n📁 ${acao.obsidian_caminho}`;

return [{ json: { ...acao, resposta_whatsapp: resposta } }];
